      call_recording_url TEXT,
      notes           TEXT,
      created_at      TEXT NOT NULL DEFAULT (datetime('now')),
      updated_at      TEXT NOT NULL DEFAULT (datetime('now'))
    );
INSERT INTO call_plans VALUES('905b8bd5-641a-4c3e-a1d9-ca1600724956','b58f75e0-5a7b-4775-8306-42b3c6702e27',NULL,'A','{"version":"1.0","generatedAt":"2026-03-21T02:37:48.289Z","target":{"companyId":"b58f75e0-5a7b-4775-8306-42b3c6702e27","companyName":"Voltage Park","companyType":"operator","contactName":null,"contactTitle":null},"script":{"version":"A","name":"Cheaper Capital","lines":["We help GPU owners get cheaper debt by reducing future collateral risk on the GPUs.","Is financing new GPU capacity a priority for you this year?","We work with structures that give lenders more comfort on residual value at maturity.","That can help improve leverage, tenor, or pricing.","Would it be useful to show you how this could fit into an existing or upcoming financing package?"],"cta":"Would it be useful to show you how this could fit into an existing or upcoming financing package?"},"decisionTree":{"nodes":{"intro":{"id":"intro","type":"speak","text":"We help GPU owners get cheaper debt by reducing future collateral risk on the GPUs.","pauseAfterMs":300,"defaultNext":"listen_interest"},"listen_interest":{"id":"listen_interest","type":"listen","promptUser":"Is financing new GPU capacity a priority for you this year?","speechTimeout":5,"branches":[{"condition":"positive","keywords":["yes","interested","tell me more","sure","go ahead","okay","sounds good"],"nextNodeId":"value_prop"},{"condition":"objection","keywords":["not interested","no thanks","don''t need","pass","not relevant","too early","not yet","not now","future","later","what is this","what exactly","explain","what do you do","tell me more","send me","email","deck","materials","information","brochure","who are you","which company","what company","corgi","already financed","have a lender","sorted","covered","wrong person","not my area","not me","someone else"],"nextNodeId":"handle_objection"},{"condition":"what_is_this","keywords":["what is this","what exactly","explain","what do you do","tell me more"],"nextNodeId":"explain_product"}],"defaultNext":"value_prop"},"value_prop":{"id":"value_prop","type":"speak","text":"We work with structures that give lenders more comfort on residual value at maturity. That can help improve leverage, tenor, or pricing.","pauseAfterMs":500,"defaultNext":"cta"},"cta":{"id":"cta","type":"speak","text":"Would it be useful to show you how this could fit into an existing or upcoming financing package?","pauseAfterMs":200,"defaultNext":"listen_cta"},"listen_cta":{"id":"listen_cta","type":"listen","speechTimeout":8,"branches":[{"condition":"accepts","keywords":["yes","sure","okay","sounds good","works","next week","book","schedule"],"nextNodeId":"book_call"},{"condition":"asks_question","keywords":["what","how","why","explain","tell me","curious"],"nextNodeId":"handle_followup"},{"condition":"declines","keywords":["no","not now","too busy","not interested","pass"],"nextNodeId":"soft_close"}],"defaultNext":"soft_close"},"explain_product":{"id":"explain_product","type":"speak","text":"It is a residual value solution for data-center GPUs. The simple purpose is to reduce lender downside on future hardware value. That can help make debt cheaper or easier to raise. On the next call, Isaac and Josh can walk through how it works in the financing stack.","pauseAfterMs":300,"defaultNext":"cta"},"handle_objection":{"id":"handle_objection","type":"branch","description":"Route to appropriate objection response based on detected intent","branches":[{"condition":"not_interested","nextNodeId":"objection_not_interested"},{"condition":"too_early","nextNodeId":"objection_too_early"},{"condition":"send_info","nextNodeId":"objection_send_info"},{"condition":"who_are_you","nextNodeId":"objection_who_are_you"},{"condition":"already_financed","nextNodeId":"objection_already_financed"},{"condition":"wrong_person","nextNodeId":"objection_wrong_person"}],"defaultNext":"objection_not_interested"},"objection_not_interested":{"id":"objection_not_interested","type":"speak","text":"Understood. Just to leave you with the short version: we reduce lender concern on GPU residual value, which can improve your financing terms. If that ever becomes relevant, I am happy to reconnect.","pauseAfterMs":400,"defaultNext":"end"},"objection_too_early":{"id":"objection_too_early","type":"speak","text":"That makes sense. Most of our conversations start 6 to 12 months before a financing process. If timing shifts, I would welcome the chance to reconnect then.","pauseAfterMs":400,"defaultNext":"followup_too_early"},"followup_too_early":{"id":"followup_too_early","type":"speak","text":"Would it be okay to follow up in a few months?","pauseAfterMs":200,"defaultNext":"end"},"objection_what_is_this":{"id":"objection_what_is_this","type":"speak","text":"It is a residual value solution for data-center GPUs. The simple purpose is to reduce lender downside on future hardware value. That can help make debt cheaper or easier to raise. On the next call, Isaac and Josh can walk through how it works in the financing stack.","pauseAfterMs":400,"defaultNext":"followup_what_is_this"},"followup_what_is_this":{"id":"followup_what_is_this","type":"speak","text":"Does that sound like something worth a 20-minute conversation with the founders?","pauseAfterMs":200,"defaultNext":"end"},"objection_send_info":{"id":"objection_send_info","type":"speak","text":"Absolutely. I will send over a short overview after this call. It covers the problem we solve and how the structure works. Would it help if I set up 20 minutes with the founders alongside the email?","pauseAfterMs":400,"defaultNext":"end"},"objection_who_are_you":{"id":"objection_who_are_you","type":"speak","text":"I am calling from Corgi. We work with GPU owners and their lenders to reduce residual value risk on hardware. That typically helps with financing terms — better leverage, longer tenor, lower spread.","pauseAfterMs":400,"defaultNext":"end"},"objection_already_financed":{"id":"objection_already_financed","type":"speak","text":"Good to hear. A lot of the conversations we have are about improving existing structures or preparing for the next facility. If you are raising again, it may be worth a quick conversation.","pauseAfterMs":400,"defaultNext":"followup_already_financed"},"followup_already_financed":{"id":"followup_already_financed","type":"speak","text":"Would it make sense to flag this for your next financing round?","pauseAfterMs":200,"defaultNext":"end"},"objection_wrong_person":{"id":"objection_wrong_person","type":"speak","text":"No problem. Who would be the right person to speak with about financing or capital structure?","pauseAfterMs":400,"defaultNext":"escalate_to_human"},"handle_followup":{"id":"handle_followup","type":"speak","text":"Great question. Are you financing owned GPUs, leased GPUs, or both?","pauseAfterMs":300,"defaultNext":"cta"},"book_call":{"id":"book_call","type":"speak","text":"Excellent. I will send you a calendar invite right after this call with a 20-minute slot with Isaac and Josh. Is there a preferred time — morning or afternoon?","pauseAfterMs":500,"defaultNext":"confirm_booking"},"confirm_booking":{"id":"confirm_booking","type":"speak","text":"Perfect. You will receive the invite shortly. Thank you for your time, and we look forward to speaking with you.","pauseAfterMs":0,"defaultNext":"end"},"soft_close":{"id":"soft_close","type":"speak","text":"Understood. I will send you a short overview by email so you can review it on your own time. If it sparks any questions, feel free to reach out.","pauseAfterMs":0,"defaultNext":"end"},"escalate_to_human":{"id":"escalate_to_human","type":"speak","text":"Thank you — I will make a note and have the right person from our team follow up directly.","pauseAfterMs":0,"defaultNext":"end"},"end":{"id":"end","type":"end","text":"Thank you for your time. Have a great day."}},"startNode":"intro"},"followUpQuestions":[{"id":"financing_type","question":"Are you financing owned GPUs, leased GPUs, or both?","triggers":["owned","leased","both","finance","financing"]},{"id":"decision_maker","question":"Who usually leads those conversations: treasury, infra, CFO, or a financing partner?","triggers":["who","person","lead","team","contact"]},{"id":"lender_friction","question":"Do lenders push back more on leverage, tenor, or pricing?","triggers":["lender","bank","push","leverage","tenor","pricing","cost"]},{"id":"current_lender_concern","question":"Do you already have a lender asking about collateral value at maturity?","triggers":["collateral","maturity","value","residual","concern"]},{"id":"scope","question":"Would you look at this for the next cluster only, or as a standard financing tool?","triggers":["next","cluster","standard","scale","expand"]}],"objectionHandlers":{"not_interested":{"triggers":["not interested","no thanks","don''t need","pass","not relevant"],"response":"Understood. Just to leave you with the short version: we reduce lender concern on GPU residual value, which can improve your financing terms. If that ever becomes relevant, I am happy to reconnect.","followUp":null,"escalate":false},"too_early":{"triggers":["too early","not yet","not now","future","later"],"response":"That makes sense. Most of our conversations start 6 to 12 months before a financing process. If timing shifts, I would welcome the chance to reconnect then.","followUp":"Would it be okay to follow up in a few months?","escalate":false},"what_is_this":{"triggers":["what is this","what exactly","explain","what do you do","tell me more"],"response":"It is a residual value solution for data-center GPUs. The simple purpose is to reduce lender downside on future hardware value. That can help make debt cheaper or easier to raise. On the next call, Isaac and Josh can walk through how it works in the financing stack.","followUp":"Does that sound like something worth a 20-minute conversation with the founders?","escalate":false},"send_info":{"triggers":["send me","email","deck","materials","information","brochure"